#include <stdio.h>
#include <stdlib.h>

void copyArray(int *arr, int len, int ***res, int *resSize) {
    (*res)[*resSize] = (int *)malloc(len * sizeof(int));
    for (int i = 0; i < len; i++) {
        (*res)[*resSize][i] = arr[i];
    }
    (*resSize)++;
}

int cmp(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

void backtrack(int *nums, int numsSize, int start, int target, int *current, int currLen, int ***res, int *resSize) {
    if (target == 0) {
        copyArray(current, currLen, res, resSize);
        return;
    }

    for (int i = start; i < numsSize; i++) {
        if (i > start && nums[i] == nums[i - 1])
            continue;

        if (nums[i] > target)
            break;

        current[currLen] = nums[i];
        backtrack(nums, numsSize, i + 1, target - nums[i], current, currLen + 1, res, resSize);
    }
}

void findCombinationSum2(int *candidateNumbers, int candidateSize, int targetSum) {
