using namespace std;

class Solution {
public:
    vector<vector<int>> findCombinationSum2(vector<int>& candidateNumbers, int targetSum) {
        sort(candidateNumbers.begin(), candidateNumbers.end());
        vector<vector<int>> result;
        vector<int> current;

        backtrack(0, targetSum, candidateNumbers, current, result);
        return result;
    }

private:
    void backtrack(int index, int target, vector<int>& nums,
                   vector<int>& current, vector<vector<int>>& result) {

        if (target == 0) {
            result.push_back(current);
            return;
        }

        for (int i = index; i < nums.size(); i++) {

            if (i > index && nums[i] == nums[i - 1])
                continue;

            if (nums[i] > target)
                break;

            current.push_back(nums[i]);
            backtrack(i + 1, target - nums[i], nums, current, result);
            current.pop_back();
        }
    }
};

