import java.util.Arrays;
import java.util.ArrayList;
import java.util.List;
import java.util.Scanner;
public class Main {
    public static List<List<Integer>> findCombinationSum2(int[] candidateNumbers, int targetSum) {
        Arrays.sort(candidateNumbers);
        List<List<Integer>> result = new ArrayList<>();
        List<Integer> current = new ArrayList<>();

        backtrack(0, targetSum, candidateNumbers, current, result);
        return result;
    }

    private static void backtrack(int index, int target, int[] nums,
                                  List<Integer> current, List<List<Integer>> result) {

        if (target == 0) {
            result.add(new ArrayList<>(current));
            return;
        }

        for (int i = index; i < nums.length; i++) {
            // Skip duplicates
            if (i > index && nums[i] == nums[i - 1])
                continue;

            if (nums[i] > target)
                break;

            current.add(nums[i]);
            backtrack(i + 1, target - nums[i], nums, current, result);
            current.remove(current.size() - 1);
        }
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        for (int t = 0; t < T; t++) {
            int n = scanner.nextInt();
            int[] candidateNumbers = new int[n];
            for (int i = 0; i < n; i++) {
                candidateNumbers[i] = scanner.nextInt();
            }
            int targetSum = scanner.nextInt();
            List<List<Integer>> result = findCombinationSum2(candidateNumbers, targetSum);
            for (List<Integer> combination : result) {
                System.out.print("[");
                for (int i = 0; i < combination.size(); i++) {
                    System.out.print(combination.get(i));
                    if (i + 1 < combination.size()) {
                        System.out.print(" ");
                    }
                }
                System.out.println("]");
            }
        }
    }
}

